class Solution:
    def kthCharacter(self, k, operations):
        word = 'a'
        for op in operations:
            if op == 0:
                word = word + word
            else:
                nxt = ''.join('a' if c == 'z' else chr(ord(c) + 1) for c in word)
                word = word + nxt
        return word[k - 1]

