class Solution:
    def kthCharacter(self, k, operations):
        n = len(operations)
        idx = k - 1
        shifts = 0
        for i in range(n - 1, -1, -1):
            half = 1 << i
            if idx >= half:
                idx -= half
                if operations[i] == 1:
                    shifts += 1
        return chr(ord('a') + shifts % 26)

