var kthCharacter = function(k, operations) {
    const n = operations.length;
    let idx = k - 1;
    let shifts = 0;
    for (let i = n - 1; i >= 0; i--) {
        const half = Math.pow(2, i);
        if (idx >= half) {
            idx -= half;
            if (operations[i] === 1) shifts++;
        }
    }
    return String.fromCharCode(97 + (shifts % 26));
};
